namespace sv_24b79c214d6541b7a71de3b7b334511d.Services;

public class AppointmentService
{
    public Task<List<string>> GetDoctorsAsync()
    {
        return Task.FromResult(new List<string>
        {
            "Dr. Smith",
            "Dr. Johnson",
            "Dr. Patel",
            "Dr. Williams"
        });
    }

    public Task<List<string>> GetAvailableTimeSlotsAsync(string doctor, DateOnly date)
    {
        // Stub: return fixed slots regardless of doctor/date
        return Task.FromResult(new List<string>
        {
            "9:00 AM",
            "10:00 AM",
            "11:00 AM",
            "1:00 PM",
            "2:00 PM",
            "3:00 PM"
        });
    }

    public Task<Dictionary<string, List<string>>> ValidatePatientAsync(
        string email,
        string insuranceProvider,
        string doctor,
        string timeSlot)
    {
        var errors = new Dictionary<string, List<string>>();

        // Reject "taken@example.com" for outstanding balance
        if (string.Equals(email, "taken@example.com", StringComparison.OrdinalIgnoreCase))
        {
            errors[nameof(AppointmentModel.Email)] = new List<string>
            {
                "Account has outstanding balance"
            };
        }

        // Reject "None" insurance with "Dr. Smith"
        if (string.Equals(insuranceProvider, "None", StringComparison.Ordinal)
            && string.Equals(doctor, "Dr. Smith", StringComparison.Ordinal))
        {
            errors[nameof(AppointmentModel.Doctor)] = new List<string>
            {
                "Selected doctor does not accept self-pay patients"
            };
        }

        // Reject "10:00 AM" as taken
        if (string.Equals(timeSlot, "10:00 AM", StringComparison.Ordinal))
        {
            errors[nameof(AppointmentModel.TimeSlot)] = new List<string>
            {
                "This slot is no longer available"
            };
        }

        return Task.FromResult(errors);
    }
}

using System.ComponentModel.DataAnnotations;

namespace sv_24b79c214d6541b7a71de3b7b334511d.Services;

public class AppointmentModel
{
    // Step 1
    [Required(ErrorMessage = "Patient name is required.")]
    public string? PatientName { get; set; }

    [Required(ErrorMessage = "Email is required.")]
    [EmailAddress(ErrorMessage = "Invalid email format.")]
    public string? Email { get; set; }

    [Required(ErrorMessage = "Phone is required.")]
    public string? Phone { get; set; }

    [Required(ErrorMessage = "Insurance provider is required.")]
    public string? InsuranceProvider { get; set; }

    // Step 2
    [Required(ErrorMessage = "Please select a doctor.")]
    public string? Doctor { get; set; }

    [Required(ErrorMessage = "Date is required.")]
    [FutureDate(ErrorMessage = "Date must be in the future.")]
    public DateOnly? AppointmentDate { get; set; }

    [Required(ErrorMessage = "Please select a time slot.")]
    public string? TimeSlot { get; set; }

    [Required(ErrorMessage = "Reason for visit is required.")]
    [StringLength(500, ErrorMessage = "Reason cannot exceed 500 characters.")]
    public string? ReasonForVisit { get; set; }
}

public class FutureDateAttribute : ValidationAttribute
{
    protected override ValidationResult? IsValid(object? value, ValidationContext validationContext)
    {
        if (value is DateOnly date && date <= DateOnly.FromDateTime(DateTime.Today))
        {
            return new ValidationResult(ErrorMessage ?? "Date must be in the future.");
        }
        return ValidationResult.Success;
    }
}

