            <label class="form-label">Time Slot</label>
            <InputSelect class="form-control" @bind-Value="Model.TimeSlot">
                <option value="">-- Select --</option>
                @foreach (var slot in timeSlots)
                {
                    <option value="@slot">@slot</option>
                }
            </InputSelect>
            <ValidationMessage For="() => Model.TimeSlot" />
        </div>

        <div class="mb-3">
            <label class="form-label">Reason for Visit</label>
            <InputTextArea class="form-control" @bind-Value="Model.ReasonForVisit" rows="4" />
            <ValidationMessage For="() => Model.ReasonForVisit" />
        </div>

        <button type="button" class="btn btn-secondary me-2" @onclick="CheckAvailability" disabled="@isSubmitting">
            @(isSubmitting ? "Checking..." : "Check Availability")
        </button>
        <button type="submit" class="btn btn-success" disabled="@(!availabilityConfirmed || isSubmitting)">
            Book Appointment
        </button>

