@code {
    private AppointmentModel Model = new();
    private EditContext? editContext;
    private CustomValidator? customValidator;

    private bool showStep2;
    private bool isSubmitting;
    private bool availabilityConfirmed;
    private bool bookingConfirmed;

    private List<string> doctors = new();
    private List<string> timeSlots = new();

    protected override async Task OnInitializedAsync()
    {
        editContext = new EditContext(Model);
        doctors = await AppointmentService.GetDoctorsAsync();
    }

    private void ProceedToStep2()
    {
        // Validate only step 1 fields
        var isValid = true;
        var step1Fields = new[] {
            nameof(AppointmentModel.PatientName),
            nameof(AppointmentModel.Email),
            nameof(AppointmentModel.Phone),
            nameof(AppointmentModel.InsuranceProvider)
        };

        foreach (var field in step1Fields)
        {
            var fi = editContext!.Field(field);
            editContext.NotifyFieldChanged(fi);
        }

        editContext.Validate();

        foreach (var field in step1Fields)
        {
            var fi = editContext!.Field(field);
            if (editContext.GetValidationMessages(fi).Any())
            {
                isValid = false;
            }
        }

        if (isValid)
        {
            showStep2 = true;
        }
    }

    private async Task OnDoctorOrDateChanged()
    {
        availabilityConfirmed = false;
        if (!string.IsNullOrEmpty(Model.Doctor) && Model.AppointmentDate.HasValue)
        {
            timeSlots = await AppointmentService.GetAvailableTimeSlotsAsync(
                Model.Doctor, Model.AppointmentDate.Value);
        }
    }

    private async Task CheckAvailability()
    {
        customValidator?.ClearErrors();
        availabilityConfirmed = false;

        // Validate step 2 fields via annotations first
        editContext!.Validate();
        var step2Fields = new[] {
            nameof(AppointmentModel.Doctor),
            nameof(AppointmentModel.AppointmentDate),
            nameof(AppointmentModel.TimeSlot),
            nameof(AppointmentModel.ReasonForVisit)
        };

        foreach (var field in step2Fields)
        {
            var fi = editContext.Field(field);
            if (editContext.GetValidationMessages(fi).Any())
            {
                return;
            }
        }

        isSubmitting = true;
        try
        {
            var errors = await AppointmentService.ValidatePatientAsync(
                Model.Email!,
                Model.InsuranceProvider!,
                Model.Doctor!,
                Model.TimeSlot!);

            if (errors.Count > 0)
            {
                customValidator!.DisplayErrors(errors);
            }
            else
            {
                availabilityConfirmed = true;
            }
        }
        finally
        {
            isSubmitting = false;
        }
    }

    private async Task HandleSubmit()
    {
        if (availabilityConfirmed)
        {
            bookingConfirmed = true;
        }
    }
}

